INSERT INTO mi_practice_modules (
    id,
    code,
    title,
    mi_focus_area,
    difficulty_level,
    estimated_minutes,
    learning_objective,
    scenario_context,
    persona_config,
    dialogue_structure,
    target_competencies,
    maps_rubric,
    is_active
) VALUES (
    '9953bad7-5f0b-4f74-9019-c4d7df240351',
    'maps-summarizing-005',
    'Module 5: Summarizing - Linking and Transitioning',
    'Eliciting Change Talk',
    'intermediate',
    20,
    'Learn to create effective summaries that gather discussions, highlight key themes, and facilitate transitions between MI processes',
    'Summaries pull together what''s been discussed, demonstrate listening, and create natural transitions. Effective summaries are: (1) Collecting - gathering what''s been said, (2) Linking - connecting themes, (3) Transitional - moving to next steps. They can strategically emphasize change talk and are offered with humility (''Let me see if I have this right...'').',
    '{"name": "When", "role": "customer", "background": "Summaries pull together what''s been discussed, demonstrate listening, and create natural transitions. Effective summaries are: (1) Collecting - gathering what''s been said, (2) Linking - connecting themes, (3) Transitional - moving to next steps. They can strategically emphasize change talk and are offered with humility (''Let me see if I have this right...'').", "personality_traits": ["neutral"], "tone_spectrum": {"word_complexity": 0.3, "sentence_length": 0.3, "emotional_expressiveness": 0.2, "disclosure_level": 0.1, "response_latency": 0.3, "confidence_level": 0.2}, "starting_tone_position": 0.2, "triggers": ["direct criticism", "being told what to do", "lecturing", "judgment"], "comfort_topics": ["autonomy", "understanding", "being heard", "personal choice"]}'::jsonb,
    '{"start_node_id": "node_1", "nodes": {"node_1": {"id": "node_1", "persona_text": "So yeah, I''ve been going back and forth on this overspending thing for weeks now. My granddaughter''s three months old already. When I''m with her, I really want to quit. But then I get stressed at work and can''t imagine getting through the day without cigarettes. I looked up some quitting methods like we talked about. Patches, gum, that prescription medication. I don''t know... it all seems complicated.", "persona_mood": "cautious_action_oriented", "themes": ["Health Concerns", "Ambivalence", "Goals", "Barriers", "Change"], "choice_points": [{"id": "cp_node_1_0", "option_text": "You''re stressed about quitting and it seems complicated.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This captures only a small part of what they shared and focuses on the negative/sustain talk side. A more complete summary would gather all the elements they mentioned.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_2a", "exploration_depth": "surface"}, {"id": "cp_node_1_1", "option_text": "Let me see if I''m following you. You''re experiencing this pull in different directions - when you''re with your granddaughter, quitting feels important and right. At work, especially under stress, overspending feels necessary. You''ve taken the step of researching methods, and now you''re weighing the complexity of the different options. How am I doing?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This collecting summary gathers the key elements: ambivalence, specific contexts, action taken, and current concerns. Asking ''How am I doing?'' invites correction and shows humility.", "learning_note": "Ambivalence is normal in change - our role is to explore it, not resolve it."}, "next_node_id": "node_2b", "exploration_depth": "surface"}, {"id": "cp_node_1_2", "option_text": "You want to quit for your granddaughter but work stress makes it hard, and you''ve researched some methods.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This is accurate and includes key elements, but it''s somewhat flat and list-like. The previous option has more depth and uses language that reflects the emotional quality of their experience.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_2c", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_2a": {"id": "node_2a", "persona_text": "Well, it''s not just that. I mean, the stress is real, but so is wanting to be around for my granddaughter. You''re making it sound like I''m just focused on the negatives.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_2a_0", "option_text": "You''re absolutely right - I missed the big picture there. Let me try again. You''re pulled between two strong forces: your granddaughter, who makes you want to quit, and work stress, where overspending feels like a necessary coping tool. And you''ve been actively researching options even while feeling uncertain. Is that more complete?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent recovery! You acknowledged the incomplete summary and offered a more balanced one that includes both change talk and sustain talk. Asking for confirmation shows respect.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_3a", "exploration_depth": "surface"}, {"id": "cp_node_2a_1", "option_text": "Right, but the stress is a major barrier for you.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Defending your incomplete summary rather than correcting it dismisses their feedback. When a customer says you missed something, believe them and adjust.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_3b", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_2b": {"id": "node_2b", "persona_text": "Yeah, that''s pretty much it. I feel like I''m in limbo. I know I need to make a decision, but I keep waiting for the ''right moment'' or for it to feel easier.", "persona_mood": "neutral_uncertain", "themes": ["Autonomy", "Goals", "Change"], "choice_points": [{"id": "cp_node_2b_0", "option_text": "So you''re in this in-between place - you know a decision is needed, but you''re waiting for conditions that would make it feel more manageable. There''s a gap between knowing and being ready.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This linking summary connects the concepts they''ve shared - the in-between place, the need for decision, the waiting, and the gap between knowing and readiness. This shows deeper understanding.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_3c", "exploration_depth": "surface"}, {"id": "cp_node_2b_1", "option_text": "You''re waiting for the right moment. What would that look like?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This is MI-adherent and the question could be useful. However, you just received confirmation of a complex situation - a summary that links themes would demonstrate deeper understanding before moving to questions.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_3d", "exploration_depth": "surface"}, {"id": "cp_node_2b_2", "option_text": "There''s never going to be a perfect moment. You just have to decide and do it.", "preview_hint": "\u26a0\ufe0f Non-MI approach", "rapport_impact": -2, "resistance_impact": 2, "tone_shift": -0.2, "technique_tags": ["righting_reflex", "confrontation"], "competency_links": [], "feedback": {"immediate": "This is the righting reflex - telling them what they need to do. It dismisses their experience and creates pressure. A summary would show understanding of their dilemma.", "learning_note": "The ''righting reflex'' (urge to fix/educate) often increases resistance in early stages."}, "next_node_id": "node_3e", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_2c": {"id": "node_2c", "persona_text": "Yeah. It''s frustrating being stuck like this. Part of me thinks I should just pick a method and try, but another part says I''m not ready.", "persona_mood": "neutral_uncertain", "themes": ["Ambivalence", "Identity"], "choice_points": [{"id": "cp_node_2c_0", "option_text": "You''re experiencing an internal tug-of-war - one voice says ''just try something'' and another says ''not yet.'' And underneath that, there''s frustration with being in this stuck place.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This linking summary names the internal conflict and connects it to the emotion (frustration). This shows you understand the complexity of their experience.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_3f", "exploration_depth": "surface"}, {"id": "cp_node_2c_1", "option_text": "Part of you wants to try and part of you doesn''t feel ready.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This is a good double-sided reflection and is MI-adherent. However, since they''ve now shared quite a bit, a fuller summary might demonstrate more complete listening than another single reflection.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_3g", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3a": {"id": "node_3a", "persona_text": "Yes, that''s much better. And honestly, the research was harder than I expected. There are so many options and everyone has opinions. My financial advisor says patches, my friend swears by the prescription medication, my wife thinks I should just quit cold turkey like her dad did.", "persona_mood": "neutral_uncertain", "themes": ["Health Concerns", "Relationships", "Barriers", "Change"], "choice_points": [{"id": "cp_node_3a_0", "option_text": "So on top of your own ambivalence about whether to quit, you''re now dealing with ambivalence about how to quit, and everyone''s well-meaning advice is adding to the confusion rather than clarity.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This linking summary shows how the confusion about methods compounds their existing ambivalence about quitting. It names the irony that advice meant to help is actually complicating things.", "learning_note": "Ambivalence is normal in change - our role is to explore it, not resolve it."}, "next_node_id": "node_4a", "exploration_depth": "surface"}, {"id": "cp_node_3a_1", "option_text": "There are a lot of options and a lot of opinions.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Accurate but doesn''t capture the emotional impact - the overwhelm and confusion. A more robust summary would show deeper understanding of their predicament.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4b", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3b": {"id": "node_3b", "persona_text": "You''re not hearing me. Yes, stress is a barrier, but you keep ignoring that I WANT to quit for my granddaughter. That matters to me.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_3b_0", "option_text": "You''re absolutely right, and I apologize. Your desire to quit for your granddaughter is significant - that''s the part that''s pulling you toward change. And it''s important to you that I understand that alongside the stress barrier. Let me make sure I''ve got both sides now.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery! You apologized, explicitly acknowledged the change talk you''d been missing, and committed to holding both sides. This repairs the relationship.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4c", "exploration_depth": "surface"}, {"id": "cp_node_3b_1", "option_text": "Okay, okay, you want to quit. I get it.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This sounds dismissive and imcustomer. When someone says you''re not hearing them, take it seriously and demonstrate that you''re truly listening now.", "learning_note": "Active listening through reflection builds trust and therapeutic alliance."}, "next_node_id": "node_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3c": {"id": "node_3c", "persona_text": "Exactly. And I''m starting to wonder if there is such a thing as a ''right moment.'' Maybe I''m just scared and making excuses.", "persona_mood": "neutral_uncertain", "themes": ["Motivation"], "choice_points": [{"id": "cp_node_3c_0", "option_text": "You''re wondering if waiting for the right moment might be a way of avoiding something that scares you. That''s an honest, uncomfortable question to ask yourself.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflects their emerging insight without pushing it. You''re honoring their self-questioning without telling them they are making excuses.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4d", "exploration_depth": "surface"}, {"id": "cp_node_3c_1", "option_text": "You are making excuses. The right moment is now.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This confronts rather than reflects. Even when a customer questions themselves, we don''t pile on. Reflect their self-awareness and let them draw their own conclusions.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4e", "exploration_depth": "surface"}, {"id": "cp_node_3c_2", "option_text": "So let me gather what we''ve talked about so far. You''re pulled between your granddaughter - who makes quitting feel important - and work stress, where overspending feels essential. You''ve researched methods, which shows you''re taking this seriously. And now you''re starting to wonder if waiting for the perfect moment might be fear in disguise. Does that capture where you are?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This comprehensive summary gathers the conversation so far and ends with their latest insight. It positions you to potentially transition to exploring what they might want to do. This is advanced summarizing.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4f", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3d": {"id": "node_3d", "persona_text": "I guess... a time when work isn''t so stressful? Or when I feel more confident I can actually do it? I don''t know. Maybe there''s no such thing.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_3d_0", "option_text": "You''ve identified what ideal conditions might look like - less stress, more confidence - and at the same time you''re doubting whether you''ll ever feel that way. So waiting might mean waiting forever.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This linking summary connects their ideal conditions with their doubt, revealing the dilemma: the conditions they''re waiting for may never arrive.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4g", "exploration_depth": "surface"}, {"id": "cp_node_3d_1", "option_text": "Right, so you should probably just do it now rather than waiting.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This is advice-giving that pushes them toward action. Instead, reflect the dilemma and let them wrestle with what it means.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4e", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3e": {"id": "node_3e", "persona_text": "Easy for you to say. You''re not the one who has to actually do it.", "persona_mood": "neutral_uncertain", "themes": ["Resistance"], "choice_points": [{"id": "cp_node_3e_0", "option_text": "You''re right - I got into telling you what to do, and that''s not helpful. Let me step back. You''re navigating this really complex situation where you''re pulled in different directions, you''ve taken steps to learn more, and you''re trying to figure out when or if you''re ready. That''s where you actually are.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery! You acknowledge the righting reflex and offer a summary that shows you actually understand their experience without prescribing action.", "learning_note": "The ''righting reflex'' (urge to fix/educate) often increases resistance in early stages."}, "next_node_id": "node_4h", "exploration_depth": "surface"}, {"id": "cp_node_3e_1", "option_text": "I''m just trying to help you see that waiting won''t make it easier.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Defending the righting reflex makes it worse. When you notice you''ve slipped into expert mode, acknowledge it and return to MI spirit.", "learning_note": "The ''righting reflex'' (urge to fix/educate) often increases resistance in early stages."}, "next_node_id": "node_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3f": {"id": "node_3f", "persona_text": "Yes! That''s exactly how it feels. And I hate feeling stuck. I''m usually pretty decisive, but this has me paralyzed.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_3f_0", "option_text": "So this stuck feeling is especially frustrating because it''s not typical for you - you usually make decisions and move forward. This one''s different, and that itself is uncomfortable.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This linking summary connects their current stuck feeling to their self-concept as a decisive person, showing why this is particularly frustrating for them.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4i", "exploration_depth": "surface"}, {"id": "cp_node_3f_1", "option_text": "Why do you think this decision is different?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This is a good open question and is MI-adherent. However, they''ve just shared a lot - a summary that gathers everything would demonstrate comprehensive listening before moving to a question.", "learning_note": "Active listening through reflection builds trust and therapeutic alliance."}, "next_node_id": "node_4j", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3g": {"id": "node_3g", "persona_text": "Right. And being stuck in the middle is exhausting. I keep going in circles.", "persona_mood": "neutral_uncertain", "themes": ["Ambivalence"], "choice_points": [{"id": "cp_node_3g_0", "option_text": "Let me see if I can pull together what you''ve shared. You''re experiencing this push and pull - your granddaughter drawing you toward quitting, work stress keeping overspending in place. You''ve researched methods, showing you''re taking this seriously. And now you''re recognizing that this circular pattern is wearing you down. Part of you wants to break out of the circle by trying something, but another part questions if you''re ready. Is that a fair summary?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This collecting summary gathers all the elements they''ve shared across the conversation and checks for accuracy. This demonstrates thorough listening and creates a foundation for moving forward.", "learning_note": "Active listening through reflection builds trust and therapeutic alliance."}, "next_node_id": "node_4k", "exploration_depth": "surface"}, {"id": "cp_node_3g_1", "option_text": "Being stuck is exhausting.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Accurate but minimal. They''ve shared quite a bit - a more comprehensive summary would show you''ve been tracking the whole conversation, not just the last thing they said.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4l", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4a": {"id": "node_4a", "persona_text": "Yes! Everyone means well, but I feel like I''m drowning in input. And then I feel guilty for not just being grateful that people care.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_4a_0", "option_text": "So there are layers here - the original decision about whether to quit, then the complexity of how to quit, then the overwhelm from everyone''s advice, and now guilt about not being more grateful for that advice. It''s getting more complicated, not simpler.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This linking summary shows how each layer adds to the previous one, creating an increasingly complex emotional and practical situation. This validates why they feel so stuck.", "learning_note": "Validation acknowledges the customer''s experience without judgment."}, "next_node_id": "node_5a", "exploration_depth": "surface"}, {"id": "cp_node_4a_1", "option_text": "What if you just told everyone to stop giving you advice?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This jumps to problem-solving without first fully understanding their situation. A summary would demonstrate understanding before exploring solutions.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5b", "exploration_depth": "surface"}, {"id": "cp_node_4a_2", "option_text": "It sounds like what you need is some space to figure out what you actually want, separate from everyone else''s opinions.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good complex reflection identifying an underlying need. Both this and the linking summary are MI-adherent - the summary demonstrates more comprehensive listening of the whole conversation.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_5c", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4b": {"id": "node_4b", "persona_text": "Yeah. Too many options, too many opinions. I thought researching would help me feel more in control, but I feel less in control now.", "persona_mood": "neutral_uncertain", "themes": ["Autonomy"], "choice_points": [{"id": "cp_node_4b_0", "option_text": "The research had the opposite effect of what you hoped - instead of creating clarity and control, it created more confusion and overwhelm. That''s got to be disappointing.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This linking summary shows how their well-intentioned action had an unintended consequence and names the emotional impact (disappointment). This shows deep empathy.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5d", "exploration_depth": "surface"}, {"id": "cp_node_4b_1", "option_text": "Sometimes less information is better.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This offers unsolicited interpretation/advice. Instead, reflect their experience and let them draw their own conclusions about what they need.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5e", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4c": {"id": "node_4c", "persona_text": "Thank you. Yes, both matter - the desire to change and the things that make it hard. I need both sides to be heard.", "persona_mood": "appreciative_engaged", "themes": ["Barriers", "Change"], "choice_points": [{"id": "cp_node_4c_0", "option_text": "So let me make sure I have the full picture now. Your granddaughter has awakened this real desire to quit - that''s the pull toward change. Work stress, and your reliance on overspending to cope with it, that''s what makes quitting feel difficult or even impossible. You''ve taken initiative to research methods, which shows you''re taking this seriously. And you''re dealing with lots of conflicting advice about how to proceed. You need all of that acknowledged - both the pull toward change and the very real barriers. How''s that?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This is a balanced collecting summary that honors both change talk and sustain talk equally. It demonstrates complete listening and invites correction. This repairs the relationship.", "learning_note": "Active listening through reflection builds trust and therapeutic alliance."}, "next_node_id": "node_5f", "exploration_depth": "surface"}, {"id": "cp_node_4c_1", "option_text": "Okay, so you want to quit for your granddaughter but work stress makes it hard.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This is accurate but too brief after they just told you how important it is to have both sides fully heard. A more comprehensive summary would show you really got the message.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5g", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4d": {"id": "node_4d", "persona_text": "It is uncomfortable. Because if I am making excuses, then what does that say about me? But if I''m genuinely not ready, then I shouldn''t push myself. I don''t know which it is.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_4d_0", "option_text": "You''re caught between two very different interpretations of your waiting - is it self-protection or self-sabotage? And that uncertainty itself is uncomfortable because it affects how you see yourself.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This linking summary captures the core dilemma and connects it to its deeper meaning - how they understand themselves. This shows sophisticated understanding.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5h", "exploration_depth": "surface"}, {"id": "cp_node_4d_1", "option_text": "Only you can know which it is.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "While technically true, this platitude doesn''t help. They''ve just shared a complex internal struggle - a summary would show you understand its depth and complexity.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5i", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4e": {"id": "node_4e", "persona_text": "Look, I don''t need you to tell me what to do. I need help figuring out what I want to do.", "persona_mood": "neutral_uncertain", "themes": ["Autonomy", "Goals"], "choice_points": [{"id": "cp_node_4e_0", "option_text": "You''re absolutely right, and I apologize for slipping into telling you what you should do. What you''re looking for is support in your own process of figuring this out, not someone directing you. Let me get back to that.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! You acknowledge the misstep, apologize, clarify their need for autonomous decision-making, and commit to returning to that approach. This honors MI spirit.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5j", "exploration_depth": "surface"}, {"id": "cp_node_4e_1", "option_text": "Fine. What do you want to do?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This sounds frustrated and puts all the burden on them. When you''ve made an error, acknowledge it genuinely before moving forward.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4f": {"id": "node_4f", "persona_text": "Yes, that''s exactly where I am. And hearing it all laid out like that... I think I''ve been avoiding really looking at whether this ''waiting'' is serving me or hurting me.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_4f_0", "option_text": "The summary helped you see something you''d been avoiding looking at directly. Where would you like to go from here with that question - whether the waiting is serving you or hurting you?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This is a transitional summary - it acknowledges what the summary just illuminated and then offers an open question about where to go next. This is advanced MI - using summary as a bridge.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5k", "exploration_depth": "surface"}, {"id": "cp_node_4f_1", "option_text": "So are you ready to stop waiting and take action?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This is a leading question that pushes toward your agenda (action). Instead, invite them to explore where they want to go with this new awareness.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5l", "exploration_depth": "surface"}, {"id": "cp_node_4f_2", "option_text": "That''s an important question to explore - whether waiting is serving you or hurting you.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good reflection. Both this and the transitional summary are MI-adherent. The transitional summary has the added benefit of explicitly inviting them to determine the direction.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_5m", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4g": {"id": "node_4g", "persona_text": "Yeah. That''s what''s scary. If I keep waiting for those conditions, I might never quit. But if I try without them... I don''t know if I''ll make it.", "persona_mood": "neutral_uncertain", "themes": ["Change"], "choice_points": [{"id": "cp_node_4g_0", "option_text": "You''re seeing the dilemma clearly now - waiting might mean never acting, but acting without ideal conditions feels like setting yourself up to fail. Both paths involve risk, just different kinds of risk.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This linking summary names the paradox - both action and inaction involve risk. This validates why the decision is so difficult.", "learning_note": "Validation acknowledges the customer''s experience without judgment."}, "next_node_id": "node_5n", "exploration_depth": "surface"}, {"id": "cp_node_4g_1", "option_text": "So what are you going to do?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This closed question pushes for a decision before they''ve fully explored the dilemma. A summary would show understanding and create space for them to continue processing.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5o", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4h": {"id": "node_4h", "persona_text": "Okay. Yeah. It is complex. And I don''t know what to do with all this complexity.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_4h_0", "option_text": "Let me see if I can help organize what you''ve shared. You''re experiencing strong pulls in different directions - your granddaughter toward change, work stress toward staying the same. You''ve researched actively, but that created more questions than answers. Everyone''s offering advice, which adds noise rather than clarity. And you''re in this in-between place, knowing you need to decide something but not clear on what or when. Given all that complexity, it makes sense you''re feeling stuck. What part of all this feels most important to focus on right now?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This comprehensive summary organizes the complexity into understandable parts, normalizes their stuck feeling given the complexity, then offers a focusing question to help them narrow down. This is sophisticated MI.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5p", "exploration_depth": "surface"}, {"id": "cp_node_4h_1", "option_text": "The complexity is the problem. Let''s simplify.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This prescribes your solution to their problem. Instead, help them organize the complexity through summary and then invite them to identify what matters most.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5q", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4i": {"id": "node_4i", "persona_text": "It is. I pride myself on being someone who makes decisions and follows through. This is out of character for me, and that makes me question myself even more.", "persona_mood": "neutral_uncertain", "themes": ["Autonomy", "Barriers"], "choice_points": [{"id": "cp_node_4i_0", "option_text": "So there''s the original struggle about overspending itself, and then there''s this layer of struggling with the struggle - questioning yourself because this doesn''t match who you understand yourself to be. That second layer adds its own weight.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This linking summary identifies that there''s the primary struggle (what to do about overspending) and a secondary struggle (what it means that they''re struggling). This meta-level insight is valuable.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5r", "exploration_depth": "surface"}, {"id": "cp_node_4i_1", "option_text": "You''re a decisive person.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["simple_reflection", "minimal"], "competency_links": ["B6"], "feedback": {"immediate": "Accurate but misses the complexity they just shared - that their current indecisiveness is challenging their self-concept. A linking summary would show deeper understanding.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5s", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4j": {"id": "node_4j", "persona_text": "I think... this one affects so much. It''s not just about me. It''s about my granddaughter, my wife, my financial, my future. The stakes feel really high.", "persona_mood": "neutral_uncertain", "themes": ["Health Concerns", "Autonomy", "Relationships", "Goals", "Barriers", "Motivation"], "choice_points": [{"id": "cp_node_4j_0", "option_text": "So let me gather what makes this decision so weighty. It''s not just about you and a habit - it''s about your granddaughter and the grandfather you want to be, your wife and her concerns, your financial and longevity, your future. All these important relationships and values are wrapped up in this one decision. That''s why it feels so much bigger than deciding about other things. Does that capture it?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This linking summary gathers all the stakes they identified and shows how they''re interconnected. It validates why this decision is uniquely difficult and checks for accuracy.", "learning_note": "Validation acknowledges the customer''s experience without judgment."}, "next_node_id": "node_5t", "exploration_depth": "surface"}, {"id": "cp_node_4j_1", "option_text": "The stakes are high.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "True but doesn''t capture what makes the stakes high - all the relationships and values involved. A more comprehensive summary would show deeper listening.", "learning_note": "Active listening through reflection builds trust and therapeutic alliance."}, "next_node_id": "node_5u", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4k": {"id": "node_4k", "persona_text": "That''s it exactly. You''ve really captured what''s going on. And honestly, hearing it all laid out like that... I think the exhaustion is telling me something. I can''t keep going in circles forever.", "persona_mood": "neutral_uncertain", "themes": ["Barriers"], "choice_points": [{"id": "cp_node_4k_0", "option_text": "The exhaustion itself is information - it''s signaling that this circular pattern isn''t sustainable. Something needs to shift. What do you think that shift might look like?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This transitional summary acknowledges their insight about the exhaustion and then invites them to explore what change might look like. This bridges from understanding to considering action.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5v", "exploration_depth": "surface"}, {"id": "cp_node_4k_1", "option_text": "Right, so you need to make a decision and commit to it.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This prescribes what they should do. They just had an insight - invite them to explore what it means rather than telling them what to do with it.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_5w", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4l": {"id": "node_4l", "persona_text": "It really is. And I''m worried I''m wasting precious time. My granddaughter is already three months old and I''m still stuck.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_4l_0", "option_text": "So to everything else, there''s now a time dimension - a sense that while you''re circling, time with your granddaughter is passing. That adds urgency to an already complex situation.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This linking summary shows how the time dimension adds another layer to an already complex situation. This validates the urgency they''re feeling.", "learning_note": "Validation acknowledges the customer''s experience without judgment."}, "next_node_id": "node_5x", "exploration_depth": "surface"}, {"id": "cp_node_4l_1", "option_text": "Then you should decide soon.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This is the righting reflex. Instead of prescribing urgency, reflect the time pressure they''re feeling and let them decide what to do with it.", "learning_note": "The ''righting reflex'' (urge to fix/educate) often increases resistance in early stages."}, "next_node_id": "node_5y", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5a": {"id": "node_5a", "persona_text": "Yes. And I don''t know how to simplify it. Do I just ignore everyone? Do I tell them to back off? I don''t want to be ungrateful or push people away.", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [{"id": "cp_node_5a_0", "option_text": "So you''re looking for a way to get some clarity and space without hurting the people who care about you. That''s a real dilemma - how to honor your need for autonomy while honoring their care and concern.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This linking summary identifies the core tension - autonomy vs. connection - and validates that it''s a real dilemma, not a simple problem to solve.", "learning_note": "Validation acknowledges the customer''s experience without judgment."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5b": {"id": "node_5b", "persona_text": "I can''t just tell people who care about me to stop caring. That''s not who I am.", "persona_mood": "neutral_uncertain", "themes": ["Barriers", "Change"], "choice_points": [{"id": "cp_node_5b_0", "option_text": "You''re right - that wouldn''t fit with your values around relationships. Let me step back. You''re dealing with caring people whose input is creating overwhelm, and you need to find your own clarity while maintaining those relationships. That''s the challenge.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good! You acknowledge the advice was wrong and offer a summary that shows you understand their actual dilemma - needing clarity while preserving relationships.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5c": {"id": "node_5c", "persona_text": "Yes. That''s exactly what I need. But I don''t know how to create that space when everyone keeps weighing in.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_5c_0", "option_text": "So the challenge is how to create internal clarity and space for your own decision-making while you''re surrounded by external input and opinions. That''s what you''re trying to figure out.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This linking summary clarifies the specific challenge they''re facing - creating internal space amid external noise. This sets up potential exploration of how to do that.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5d": {"id": "node_5d", "persona_text": "It is disappointing. I thought I was being smart and proactive, and instead I just made myself more confused.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_5d_0", "option_text": "Your intention was good - to make an informed, thoughtful decision. The unintended consequence was overwhelm. So now the question is how to use what you learned without being paralyzed by it.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This validates their good intention, acknowledges the unintended outcome, and gently frames the next question without prescribing an answer.", "learning_note": "Validation acknowledges the customer''s experience without judgment."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5e": {"id": "node_5e", "persona_text": "Maybe. But I also think I need to know what I''m getting into. I just... I need to process it all somehow.", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [{"id": "cp_node_5e_0", "option_text": "You''re caught between two needs - the need to be informed and the need to not be overwhelmed. Both are valid. You''re trying to figure out how to honor both.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good! This linking summary shows the tension between competing valid needs and validates the challenge of honoring both.", "learning_note": "Validation acknowledges the customer''s experience without judgment."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5f": {"id": "node_5f", "persona_text": "Yes, that''s much better. That''s the full picture. And now that I hear it all together... I realize the desire to quit is actually pretty strong. It''s the ''how'' that scares me, not the ''whether.''", "persona_mood": "neutral_uncertain", "themes": ["Motivation", "Change"], "choice_points": [{"id": "cp_node_5f_0", "option_text": "That''s a significant realization - when you see the whole picture, you recognize that the desire is there. The uncertainty is more about whether you can do it and how to do it than whether you want to. That''s an important distinction.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This transitional summary highlights the important shift they just identified - from ambivalence about wanting to change to uncertainty about ability/method. This is readiness emerging.", "learning_note": "Ambivalence is normal in change - our role is to explore it, not resolve it."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5g": {"id": "node_5g", "persona_text": "That''s still too simple. There''s more to it than that.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_5g_0", "option_text": "You''re right. Let me be more thorough. You have this desire to quit for your granddaughter - that''s real and important. Work stress and how you rely on overspending to cope with it makes quitting feel daunting. You''ve researched methods, showing you''re serious about this. And you''re dealing with a lot of input from others. All of that is part of the picture, and all of it needs to be acknowledged.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good! You responded to their feedback by providing a more comprehensive summary that gathers the key elements.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5h": {"id": "node_5h", "persona_text": "Exactly. Am I being wise and self-aware, or am I being a coward? I keep going back and forth on that too.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_5h_0", "option_text": "That oscillation between self-compassion and self-judgment is another circle you''re caught in - on top of the circle about whether to quit. These layers of circling make it even harder to find solid ground.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This linking summary shows how the self-judgment creates another layer of circling on top of the ambivalence about overspending. This validates why finding clarity is so difficult.", "learning_note": "Ambivalence is normal in change - our role is to explore it, not resolve it."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5i": {"id": "node_5i", "persona_text": "That''s not helpful. I know only I can know. I''m asking for help figuring it out.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_5i_0", "option_text": "You''re right, that was a platitude and not helpful. What you''re asking for is support in exploring this question - is your hesitation self-protection or avoidance? That''s a hard question to answer, and you want to think it through rather than be told the answer. Let me help you explore it.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery! You acknowledge the unhelpful platitude and clarify their need - support in exploration, not answers. This returns to MI spirit.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5j": {"id": "node_5j", "persona_text": "Thank you. I appreciate that. What I''m looking for is someone to help me think through this, not someone to tell me what the answer is.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_5j_0", "option_text": "I understand, and I''m here to help you think through it. Let me make sure I''m with you on where things stand. You''re experiencing pulls in different directions, you''ve researched actively, you''re dealing with lots of input, and you''re trying to sort through what you genuinely want versus what others want for you. Does that capture the complexity you''re working through?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! You confirm your role, then offer a summary that demonstrates you understand their situation. This rebuilds the collaborative relationship.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5k": {"id": "node_5k", "persona_text": "I think... I think the waiting is hurting me. It''s keeping me stuck, and I''m using ''not being ready'' as an excuse to avoid the discomfort of actually trying.", "persona_mood": "neutral_uncertain", "themes": ["Change"], "choice_points": [{"id": "cp_node_5k_0", "option_text": "That''s a courageous thing to acknowledge - that the waiting might be protective against discomfort but is keeping you stuck in a place you don''t want to be. What does recognizing that make you think about doing?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This affirms their courage in facing this truth and then invites them to explore what action might follow from this awareness. This is transitioning from contemplation to preparation.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5l": {"id": "node_5l", "persona_text": "Don''t put words in my mouth. I didn''t say I was ready to take action. I said I realized something about my waiting.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_5l_0", "option_text": "You''re absolutely right - I jumped ahead again. You had an insight about your waiting, and that''s significant on its own. Where you go with that insight is up to you, not me.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery! You acknowledge jumping ahead and explicitly honor their autonomy about what to do with their insight.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5m": {"id": "node_5m", "persona_text": "It is. And I''m not sure what the answer is yet, but at least now I know what the question is.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_5m_0", "option_text": "So our conversation has helped you move from confusion to clarity - not clarity about the answer yet, but clarity about the real question you''re wrestling with. That''s meaningful progress.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This transitional summary acknowledges the value of gaining clarity about the question, validating that this is real progress even without having an answer yet.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5n": {"id": "node_5n", "persona_text": "Yes. Both feel risky. I guess... I guess the question is which risk I''d rather take. Or which risk I can live with if it doesn''t work out.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_5n_0", "option_text": "That''s a shift - from trying to find a risk-free path to recognizing you need to choose which risk makes sense for you. That''s a more realistic and empowered way to think about it.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This transitional summary names an important cognitive shift - from avoidance to active choice. This is movement toward readiness.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5o": {"id": "node_5o", "persona_text": "I don''t know yet. That''s what I''m trying to figure out.", "persona_mood": "neutral_uncertain", "themes": ["Autonomy"], "choice_points": [{"id": "cp_node_5o_0", "option_text": "Let me step back. You''re seeing this dilemma clearly now - both waiting and acting involve risk. You''re still in the process of weighing those risks and what they mean for you. You''re not at decision yet, you''re at understanding. Is that right?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery! This summary shows you understand they''re still in the weighing/understanding phase, not the decision phase. This honors their process.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5p": {"id": "node_5p", "persona_text": "I think... I think the most important part is figuring out how I cope with stress if not overspending. That''s the piece that scares me most.", "persona_mood": "neutral_uncertain", "themes": ["Health Concerns", "Motivation"], "choice_points": [{"id": "cp_node_5p_0", "option_text": "So of all the complexity, the question that rises to the top for you is: how would you manage stress without cigarettes? That''s the core concern that needs addressing before you can move forward.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This focusing summary shows how the comprehensive discussion has helped them identify the core issue. This is advanced MI - using summary to help clarify what matters most.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5q": {"id": "node_5q", "persona_text": "It''s not that simple. The complexity is real. I can''t just ignore it.", "persona_mood": "neutral_uncertain", "themes": ["Barriers"], "choice_points": [{"id": "cp_node_5q_0", "option_text": "You''re right - the complexity is real and important. Let me try a different approach. What I hear you saying is that you''re dealing with multiple layers - the decision itself, the methods, the input from others, your own self-judgment. Rather than simplifying, what might help is identifying which layer feels most important to address first. Does that make sense?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery! You acknowledge the complexity, organize it into layers, and invite them to identify what matters most rather than prescribing simplification.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5r": {"id": "node_5r", "persona_text": "Yes! There''s the problem itself and then there''s what it means that I''m having this problem. Both are hard.", "persona_mood": "neutral_uncertain", "themes": ["Barriers"], "choice_points": [{"id": "cp_node_5r_0", "option_text": "You''re carrying a double weight - the actual struggle with overspending and what that struggle means about you as a person. That''s a lot. And recognizing that second layer exists is important, because maybe addressing both requires different approaches.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This validates the double burden and gently suggests that seeing the two layers clearly might help address them differently. This is sophisticated guidance without prescription.", "learning_note": "Validation acknowledges the customer''s experience without judgment."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5s": {"id": "node_5s", "persona_text": "I usually am. But not about this. And I don''t know why this is so different.", "persona_mood": "neutral_uncertain", "themes": ["Barriers", "Motivation", "Change"], "choice_points": [{"id": "cp_node_5s_0", "option_text": "So there''s something about this particular decision that''s different from how you usually operate, and that difference itself is puzzling to you. Part of what you''re trying to understand is not just what to do about overspending but why this decision feels so different from others.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good! This linking summary shows how they''re wrestling with two questions - what to do and why it''s so hard. This validates the meta-level confusion.", "learning_note": "Validation acknowledges the customer''s experience without judgment."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5t": {"id": "node_5t", "persona_text": "Yes, exactly. It''s all connected. I can''t make this decision in isolation because it affects everyone and everything I care about.", "persona_mood": "neutral_uncertain", "themes": ["Autonomy", "Barriers"], "choice_points": [{"id": "cp_node_5t_0", "option_text": "So this decision sits at the center of a web of relationships and values - you can''t pull one thread without affecting the whole web. That''s why it feels so weighty and why simple answers don''t work. You need a decision that honors all these connections.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Beautiful! This linking summary uses the web metaphor to capture how interconnected everything is and validates why this requires careful thought. This is sophisticated empathy.", "learning_note": "Validation acknowledges the customer''s experience without judgment."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5u": {"id": "node_5u", "persona_text": "They are. And knowing the stakes are high doesn''t make the decision easier - it makes it harder.", "persona_mood": "neutral_uncertain", "themes": ["Autonomy", "Barriers"], "choice_points": [{"id": "cp_node_5u_0", "option_text": "That''s the paradox - the very importance of this decision, all these relationships and values at stake, that makes it more difficult rather than clearer. The weight of the decision is both motivation and burden.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This linking summary names the paradox - high stakes create both motivation and paralysis. This validates their experience.", "learning_note": "Validation acknowledges the customer''s experience without judgment."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5v": {"id": "node_5v", "persona_text": "I don''t know exactly, but I know I can''t just keep thinking about it in circles. Maybe I need to try something, even if I''m not 100% ready. Maybe readiness comes from doing, not from thinking.", "persona_mood": "cautious_action_oriented", "themes": ["Goals", "Barriers", "Change"], "choice_points": [{"id": "cp_node_5v_0", "option_text": "That''s a significant shift in your thinking - from ''I need to be ready before I act'' to ''maybe acting is how I become ready.'' You''re considering that movement might create clarity rather than clarity creating movement. That''s a different way of approaching this.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This transitional summary captures a major cognitive shift that often precedes behavior change - from preparation to action. This is exactly the kind of change talk that suggests readiness emerging.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5w": {"id": "node_5w", "persona_text": "That''s not what I said. I said something needs to shift. I didn''t say it needs to be a decision right now.", "persona_mood": "neutral_uncertain", "themes": ["Autonomy"], "choice_points": [{"id": "cp_node_5w_0", "option_text": "You''re right - I pushed you toward a specific kind of shift (decision and commitment) when you said something more open (''something needs to shift''). What kind of shift do you think needs to happen?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery! You acknowledge prescribing your interpretation and invite them to clarify what kind of shift they mean.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5x": {"id": "node_5x", "persona_text": "Yes. I don''t want to look back in five years and realize I wasted all this time being stuck when I could have been smoke-free and present with her.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_5x_0", "option_text": "That''s a powerful motivator - the image of future regret, of lost time you can''t get back with your granddaughter. That feels more urgent than the theoretical financial risks. It''s personal and immediate.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This linking summary amplifies their change talk and contrasts it with abstract financial concerns - showing that this particular motivation (lost time with granddaughter) carries special weight for them.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_5y": {"id": "node_5y", "persona_text": "Don''t tell me what I should do. I''m sharing what I''m feeling.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_5y_0", "option_text": "I apologize. You were sharing an important feeling - the sense of time passing and opportunities with your granddaughter slipping by. That urgency is real for you, and it''s not my place to tell you what to do with it.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good! You apologize for the righting reflex and reflect their feeling without prescribing action. This returns to MI spirit.", "learning_note": "The ''righting reflex'' (urge to fix/educate) often increases resistance in early stages."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_end_good": {"id": "node_end_good", "persona_text": "This conversation has been really helpful. You helped me organize my thinking and see things I wasn''t seeing before. I feel like I have more clarity about what I''m actually dealing with, even if I don''t have all the answers yet.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [], "is_endpoint": true, "endpoint_type": "neutral_end"}, "node_end_moderate": {"id": "node_end_moderate", "persona_text": "Thanks for listening and for correcting course when I pointed out you were getting off track. That helps.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [], "is_endpoint": true, "endpoint_type": "neutral_end"}, "node_end_poor": {"id": "node_end_poor", "persona_text": "This isn''t helpful. I don''t think we''re on the same page here.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [], "is_endpoint": true, "endpoint_type": "failed_engagement"}}}'::jsonb,
